<template><el-card><template #header>{{ title }}</template><PageToolbar><el-input v-model="keyword" placeholder="关键词搜索" clearable /><el-select v-model="status" placeholder="状态" clearable><el-option label="已发布" value="已发布"/><el-option label="审核中" value="审核中"/></el-select><template #actions><el-button type="primary" @click="dialog=true">新建</el-button><el-button>导出</el-button></template></PageToolbar><DataTable :data="rows"><el-table-column prop="name" label="名称" min-width="220"/><el-table-column prop="type" label="类型"/><el-table-column prop="domain" label="业务域"/><el-table-column prop="status" label="状态"/><el-table-column prop="time" label="更新时间"/><el-table-column label="操作" width="220"><template #default="s"><el-button link type="primary" @click="detail=s.row">详情</el-button><el-button link type="warning" @click="s.row.status='审核中'">提交审核</el-button><el-button link type="success" @click="s.row.status='已发布'">发布</el-button></template></el-table-column></DataTable><DetailDrawer v-model="open" :title="detail?.name || '详情'"><pre>{{detail}}</pre></DetailDrawer><el-dialog v-model="dialog" title="新建配置" width="520"><el-form label-width="100"><el-form-item label="名称"><el-input v-model="form.name" /></el-form-item><el-form-item label="说明"><el-input type="textarea" v-model="form.desc" /></el-form-item></el-form><template #footer><el-button @click="dialog=false">取消</el-button><el-button type="primary" @click="add">保存</el-button></template></el-dialog></el-card></template>
<script setup lang="ts">import { computed, ref, watch } from 'vue'; import { useRoute } from 'vue-router'; import { titleByPath } from '@/router/menu'; import PageToolbar from '@/components/PageToolbar.vue'; import DataTable from '@/components/DataTable.vue'; import DetailDrawer from '@/components/DetailDrawer.vue'; const route=useRoute(); const title=computed(()=>titleByPath(route.path).at(-1)); const keyword=ref(''); const status=ref(''); const dialog=ref(false); const detail=ref<any>(); const open=computed({get:()=>!!detail.value,set:v=>{if(!v)detail.value=undefined}}); const form=ref({name:'',desc:''}); const rows=ref<any[]>([]); function reset(){rows.value=Array.from({length:6},(_,i)=>({name:`${title.value}演示数据 ${i+1}`,type:['配置','日志','策略'][i%3],domain:['光伏并网','电价政策','客户服务'][i%3],status:['已发布','审核中','草稿'][i%3],time:`2026-05-${20+i} 10:00`}))} watch(()=>route.path,reset,{immediate:true}); function add(){ rows.value.unshift({name:form.value.name||'新建项',type:'配置',domain:'通用',status:'草稿',time:'刚刚'}); dialog.value=false; }</script>
